"""SQLite-backed telemetry store for orchestrated agent runs."""

from __future__ import annotations

import json
import os
import sqlite3
from contextlib import contextmanager
from datetime import datetime
from typing import Any, Dict, Generator, List, Optional

APP_ROOT = os.path.dirname(os.path.dirname(__file__))
DATA_DIR = os.path.join(APP_ROOT, "data")
DB_PATH = os.path.join(DATA_DIR, "telemetry.db")


def _ensure_db() -> None:
    os.makedirs(DATA_DIR, exist_ok=True)
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS runs (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at TEXT NOT NULL,
                kind TEXT NOT NULL,
                payload TEXT,
                trace TEXT,
                validation TEXT,
                sources TEXT,
                duration_ms REAL,
                chunk_count INTEGER
            )
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_runs_created_at
            ON runs(created_at DESC)
            """
        )


@contextmanager
def _get_conn() -> Generator[sqlite3.Connection, None, None]:
    _ensure_db()
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    try:
        yield conn
    finally:
        conn.close()


def log_run(
    *,
    kind: str,
    payload: Dict[str, Any],
    trace: List[Dict[str, Any]],
    validation: Optional[Dict[str, Any]],
    sources: Optional[List[Dict[str, Any]]],
    duration_ms: Optional[float],
    chunk_count: Optional[int],
) -> None:
    record = (
        datetime.utcnow().isoformat(),
        kind,
        json.dumps(payload, ensure_ascii=False),
        json.dumps(trace, ensure_ascii=False),
        json.dumps(validation, ensure_ascii=False) if validation is not None else None,
        json.dumps(sources, ensure_ascii=False) if sources is not None else None,
        duration_ms,
        chunk_count,
    )
    with _get_conn() as conn:
        conn.execute(
            """
            INSERT INTO runs (
                created_at, kind, payload, trace, validation, sources, duration_ms, chunk_count
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            record,
        )
        conn.commit()


def fetch_recent(limit: int = 25) -> List[Dict[str, Any]]:
    with _get_conn() as conn:
        rows = conn.execute(
            "SELECT id, created_at, kind, payload, trace, validation, sources, duration_ms, chunk_count \
             FROM runs ORDER BY datetime(created_at) DESC LIMIT ?",
            (limit,),
        ).fetchall()

    events: List[Dict[str, Any]] = []
    for row in rows:
        events.append(
            {
                "id": row[0],
                "created_at": row[1],
                "kind": row[2],
                "payload": json.loads(row[3]) if row[3] else {},
                "trace": json.loads(row[4]) if row[4] else [],
                "validation": json.loads(row[5]) if row[5] else None,
                "sources": json.loads(row[6]) if row[6] else [],
                "duration_ms": row[7],
                "chunk_count": row[8],
            }
        )
    return events
